    static_assert(K <= 4096,
        "K must fit in threadgroup memory.");
    static_assert(K >= 256,
        "K must be >= 256 for Q4 uint32 path.");
    static_assert(group_size % 8 == 0,
        "Group size must be 8-aligned.");
    static_assert(K % 512 == 0,
        "K must be divisible by 512 "
